    studies: [{"title": "Effect of Urolithin A Supplementation on Muscle Endurance and Mitochondrial Health (Singh et al.)", "authors": "Singh, D'Amico et al.", "year": 2022, "journal": "JAMA Network Open", "design": "ECA", "n": 88, "url": "https://jamanetwork.com/journals/jamanetworkopen/fullarticle/2789995", "finding": "4 meses de urolitina A 500/1000 mg mejoraron la resistencia muscular y los biomarcadores mitocondriales frente a placebo en adultos de mediana edad.", "limitations": "Criterios de valoración sustitutos; financiado por la industria."}, {"title": "The mitophagy activator urolithin A is safe and induces a molecular signature of improved mitochondrial and cellular health in humans (Andreux et al.)", "authors": "Andreux et al.", "year": 2019, "journal": "Nature Metabolism", "design": "ECA", "n": 60, "url": "https://www.nature.com/articles/s42255-019-0073-4", "finding": "Primera seguridad en humanos + confirmación de biomarcadores de mejora de la firma mitocondrial.", "limitations": "Corta duración; biomarcadores."}],
