    studies: [{"title": "The effect of garlic on blood pressure: an updated meta-analysis", "authors": "Ried K", "year": 2016, "journal": "J Nutr", "design": "Metanálisis (20 ECA)", "n": 970, "url": "https://pubmed.ncbi.nlm.nih.gov/?term=The%20effect%20of%20garlic%20on%20blood%20pressure%3A%20an%20updated%20meta-analysis", "finding": "La suplementación con ajo redujo la presión arterial sistólica en 5,1 mmHg y la diastólica en 2,5 mmHg frente al placebo en 20 ECA. El efecto se duplicó en sujetos hipertensos.", "limitations": "Preparaciones de ajo heterogéneas entre los estudios. Seguimiento medio de 12 semanas: el efecto de la PA a largo plazo es menos seguro."}, {"title": "Aged garlic extract reduces low attenuation plaque in coronary arteries", "authors": "Matsumoto S, Nakanishi R, Li D, Alani A, Rezaeian P, Prabhu S, Abraham J, Fahmy MA, Dailing C, Flores F, Hamal S, Broersen A, Kitslaar PH, Budoff MJ", "year": 2016, "journal": "J Nutr", "design": "ECA (12 meses, ATC coronaria)", "n": 55, "url": "https://pubmed.ncbi.nlm.nih.gov/?term=Aged%20garlic%20extract%20reduces%20low%20attenuation%20plaque%20in%20coronary%20arteries", "finding": "El extracto de ajo añejo ralentizó la progresión de la placa de baja atenuación (vulnerable) medida mediante TC coronaria frente a placebo durante 12 meses. La progresión total de la placa también se redujo.", "limitations": "Pequeña muestra. Criterio de valoración sustituto (placa de TC, no eventos). Financiado por la industria (Wakunaga)."}],
