    studies: [{"title": "An alternative treatment for anxiety: a systematic review of human trial results reported for the Ayurvedic herb ashwagandha", "authors": "Pratte MA, Nanavati KB, Young V, Morley CP", "year": 2014, "journal": "J Altern Complement Med", "design": "Revisión sistemática (5 ECA)", "n": 400, "url": "https://pubmed.ncbi.nlm.nih.gov/25405876/", "finding": "En 5 ECA, la ashwagandha redujo consistentemente las escalas de ansiedad y estrés en comparación con el placebo. Los tamaños del efecto son moderados (d de Cohen ~0,7).", "limitations": "Todos los ensayos fueron cortos (≤12 semanas). La mayoría financiados por la industria. Extractos y dosis heterogéneos."}, {"title": "A standardized Withania somnifera extract significantly reduces stress-related parameters in chronically stressed humans: a double-blind, randomized, placebo-controlled study", "authors": "Auddy B, Hazra J, Mitra A, Abedon B, Ghosal S", "year": 2008, "journal": "JANA", "design": "ECA (60 días)", "n": 130, "url": "https://www.researchgate.net/publication/255697008", "finding": "El extracto de Ashwagandha 125-500 mg/día redujo las puntuaciones de PSS en un 44 %, el cortisol sérico en un 26 % y mejoró las puntuaciones de PCR y bienestar en comparación con el placebo.", "limitations": "Financiado por la industria (Natreon). Población india de un solo sitio. Corta duración."}],
