    studies: [{"title": "Effect of NMN on physical performance in older adults: RCT", "authors": "Yamaguchi et al.", "year": 2022, "journal": "Nutrients", "design": "ECA", "n": 108, "url": "https://www.mdpi.com/2072-6643/14/4/755", "finding": "12 semanas de NMN 250 mg/día mejoraron la distancia recorrida y la fuerza de agarre en comparación con el placebo en adultos mayores de 65 años.", "limitations": "Corta duración; criterios de valoración sustitutos."}, {"title": "Chronic NMN supplementation elevates blood NAD+ in healthy middle-aged adults (Yoshino et al.)", "authors": "Yoshino, Baur et al.", "year": 2021, "journal": "Science", "design": "ECA", "n": 25, "url": "https://www.science.org/doi/10.1126/science.abe9985", "finding": "10 semanas de NMN 250 mg/día mejoraron la sensibilidad a la insulina en el músculo esquelético de mujeres posmenopáusicas con prediabetes.", "limitations": "Pequeña N; solo mujeres."}],
