    studies: [{"title": "Ergothioneine in human plasma is inversely associated with mortality (Smith et al.)", "authors": "Smith et al.", "year": 2020, "journal": "Heart", "design": "cohorte", "n": 3236, "url": "https://heart.bmj.com/content/106/9/691", "finding": "Una mayor ergotioneína plasmática se asoció con un 21 % menos de mortalidad por todas las causas y un 26 % menos de mortalidad CV (Malmo Diet and Cancer Study).", "limitations": "De observación; a base de alimentos."}],
