    studies: [{"title": "Senolytics decrease senescent cells in humans (Hickson et al.)", "authors": "Hickson et al.", "year": 2019, "journal": "EBioMedicine", "design": "Etiqueta abierta", "n": 9, "url": "https://www.thelancet.com/journals/ebiom/article/PIIS2352-3964(19)30591-2/fulltext", "finding": "D+Q redujo los marcadores de células senescentes en el tejido adiposo de pacientes diabéticos con enfermedad renal.", "limitations": "Pequeña N; Solo biomarcador."}],
