    studies: [{"title": "Resveratrol does not extend lifespan in genetically heterogeneous mice (ITP)", "authors": "Strong et al.", "year": 2013, "journal": "J Gerontol A Biol Sci Med Sci", "design": "ECA (ratones)", "n": 1000, "url": "https://academic.oup.com/biomedgerontology/article/68/1/6/615625", "finding": "No hay extensión de la vida útil en ninguna de las dosis probadas. Resultado negativo reproducido en todos los sitios ITP.", "limitations": "Sólo ratón; genotipo específico."}, {"title": "Resveratrol: small molecule, big effect? (review)", "authors": "Smoliga, Baur, Hausenblas", "year": 2011, "journal": "Mol Nutr Food Res", "design": "Revisión", "n": null, "url": "https://onlinelibrary.wiley.com/doi/10.1002/mnfr.201100143", "finding": "Evidencia humana mixta; Se observa una brecha en la evidencia exagerada.", "limitations": "Revisión narrativa."}],
