    studies: [{"title": "Acarbose, 17-α-estradiol, and nordihydroguaiaretic acid extend mouse lifespan (ITP, Harrison 2014)", "authors": "Harrison, Strong, Allison et al.", "year": 2014, "journal": "Aging Cell", "design": "ECA (ratones)", "n": 1500, "url": "https://onlinelibrary.wiley.com/doi/10.1111/acel.12170", "finding": "El 17α-estradiol comenzó a los 10 meses y amplió la esperanza de vida masculina promedio ~19%. Sin efecto femenino.", "limitations": "Sólo ratón; específico del sexo."}, {"title": "17α-Estradiol Acts Through Hepatic mTOR Signaling (Garratt et al.)", "authors": "Garratt et al.", "year": 2017, "journal": "Aging Cell", "design": "mecanicista", "n": null, "url": "https://onlinelibrary.wiley.com/doi/10.1111/acel.12625", "finding": "Las mejoras en la sensibilidad a la insulina hepática mTORC2 + parecen mediar en el beneficio específico para los hombres.", "limitations": "Sólo mecanismo; ratón."}],
